import { GoogleGenAI, Type } from "@google/genai";
import { VocabWord } from '../types';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const generateVocabData = async (rawWords: string[]): Promise<VocabWord[]> => {
  if (rawWords.length === 0) return [];
  if (!process.env.API_KEY) {
    console.warn("No API Key found. Returning mock data.");
    return [];
  }

  const prompt = `
    I have a list of vocabulary words for a 10-year-old student.
    Words: ${rawWords.join(', ')}.

    For EACH word, generate a JSON object with:
    1. The word itself.
    2. A clear, age-appropriate definition.
    3. A sentence using the word, but replace the word (and any variations like suffix -ing, -ed) with "______".
    4. 3 Synonyms.
    5. 3 "Distractors" (fake definitions that look plausible but are clearly wrong, for a multiple choice quiz).

    Return ONLY a JSON array.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              word: { type: Type.STRING },
              definition: { type: Type.STRING },
              sentence: { type: Type.STRING },
              synonyms: { type: Type.ARRAY, items: { type: Type.STRING } },
              distractors: { type: Type.ARRAY, items: { type: Type.STRING } }
            }
          }
        }
      }
    });

    const text = response.text;
    if (!text) return [];

    const parsed = JSON.parse(text);

    return parsed.map((item: any, index: number) => ({
      id: `${Date.now()}-${index}`,
      word: item.word,
      definition: item.definition,
      sentence: item.sentence,
      synonyms: item.synonyms,
      distractors: item.distractors,
      masteryLevel: 0
    }));

  } catch (error) {
    console.error("Error generating vocab data:", error);
    throw new Error("Failed to generate word data. Please check your API key.");
  }
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger' | 'success' | 'ghost';
  size?: 'sm' | 'md' | 'lg';
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  size = 'md', 
  className = '', 
  ...props 
}) => {
  const baseStyles = "font-bold rounded-xl transition-all active:scale-95 flex items-center justify-center gap-2 shadow-sm border-b-4";

  const variants = {
    primary: "bg-indigo-500 hover:bg-indigo-400 text-white border-indigo-700",
    secondary: "bg-slate-700 hover:bg-slate-600 text-white border-slate-900",
    danger: "bg-red-500 hover:bg-red-400 text-white border-red-700",
    success: "bg-green-500 hover:bg-green-400 text-white border-green-700",
    ghost: "bg-transparent hover:bg-white/10 text-white border-transparent shadow-none"
  };

  const sizes = {
    sm: "px-3 py-1 text-sm",
    md: "px-6 py-3 text-base",
    lg: "px-8 py-4 text-xl"
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${sizes[size]} ${className}`} 
      {...props}
    >
      {children}
    </button>
  );
};

