import React, { useState, useEffect } from 'react';
import { VocabWord, QuestionType, UserProfile } from '../types';
import { Button } from './ui/Button';
import { CheckCircle, XCircle, Sword, Trophy } from 'lucide-react';
import confetti from 'canvas-confetti';

interface BattleArenaProps {
  words: VocabWord[];
  onComplete: (score: number, goldEarned: number, xpEarned: number) => void;
  onExit: () => void;
}

export const BattleArena: React.FC<BattleArenaProps> = ({ words, onComplete, onExit }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [score, setScore] = useState(0);
  const [selectedAnswer, setSelectedAnswer] = useState<string | null>(null);
  const [isCorrect, setIsCorrect] = useState<boolean | null>(null);
  const [gameWords, setGameWords] = useState<VocabWord[]>([]);
  const [options, setOptions] = useState<string[]>([]);
  const [qType, setQType] = useState<QuestionType>(QuestionType.DEFINITION);

  // Initialize game
  useEffect(() => {
    // Shuffle words and pick up to 10
    const shuffled = [...words].sort(() => 0.5 - Math.random());
    setGameWords(shuffled.slice(0, 10));
  }, [words]);

  // Setup options when index changes
  useEffect(() => {
    if (gameWords.length === 0) return;

    const currentWord = gameWords[currentIndex];
    // Randomize Question Type
    const types = [QuestionType.DEFINITION, QuestionType.FILL_BLANK];
    const type = types[Math.floor(Math.random() * types.length)];
    setQType(type);

    let opts: string[] = [];

    if (type === QuestionType.DEFINITION) {
      // 1 Correct definition + 3 Distractors
      opts = [currentWord.definition, ...currentWord.distractors];
    } else {
      // Fill blank: 1 correct word + 3 random other words from the list
      const otherWords = words
        .filter(w => w.id !== currentWord.id)
        .map(w => w.word)
        .sort(() => 0.5 - Math.random())
        .slice(0, 3);
      opts = [currentWord.word, ...otherWords];
    }

    // Shuffle options
    setOptions(opts.sort(() => 0.5 - Math.random()));
    setSelectedAnswer(null);
    setIsCorrect(null);
  }, [currentIndex, gameWords, words]);

  const handleAnswer = (ans: string) => {
    if (selectedAnswer) return; // Prevent double click

    setSelectedAnswer(ans);
    const currentWord = gameWords[currentIndex];
    let correct = false;

    if (qType === QuestionType.DEFINITION) {
      correct = ans === currentWord.definition;
    } else {
      correct = ans === currentWord.word;
    }

    setIsCorrect(correct);

    if (correct) {
      confetti({
        particleCount: 50,
        spread: 70,
        origin: { y: 0.6 }
      });
      setScore(s => s + 100);
      // Play sound?
    }
  };

  const nextQuestion = () => {
    if (currentIndex < gameWords.length - 1) {
      setCurrentIndex(prev => prev + 1);
    } else {
      // End Game
      const gold = Math.floor(score / 5);
      const xp = score;
      onComplete(score, gold, xp);
    }
  };

  if (gameWords.length === 0) return <div className="p-10 text-center">Loading Battle...</div>;

  const currentWord = gameWords[currentIndex];
  const progress = ((currentIndex) / gameWords.length) * 100;

  return (
    <div className="flex flex-col h-full max-w-2xl mx-auto w-full p-4">
      {/* Header */}
      <div className="flex justify-between items-center mb-6">
        <Button size="sm" variant="secondary" onClick={onExit}>Exit Battle</Button>
        <div className="flex items-center gap-2 bg-slate-800 px-4 py-2 rounded-full">
          <Trophy className="text-yellow-400 w-5 h-5" />
          <span className="font-bold text-xl">{score}</span>
        </div>
      </div>

      {/* Progress Bar */}
      <div className="w-full bg-slate-700 h-3 rounded-full mb-8">
        <div 
          className="bg-green-500 h-3 rounded-full transition-all duration-300"
          style={{ width: `${progress}%` }}
        ></div>
      </div>

      {/* Question Card */}
      <div className="bg-slate-800 rounded-3xl p-8 shadow-xl border-b-8 border-slate-950 flex-grow flex flex-col items-center justify-center text-center relative overflow-hidden">

        {/* Decoration */}
        <div className="absolute top-[-50px] right-[-50px] w-32 h-32 bg-indigo-500 rounded-full opacity-20 blur-xl"></div>
        <div className="absolute bottom-[-50px] left-[-50px] w-32 h-32 bg-purple-500 rounded-full opacity-20 blur-xl"></div>

        <h2 className="text-gray-400 font-bold uppercase tracking-wider mb-4">
          {qType === QuestionType.DEFINITION ? 'Find the Definition' : 'Complete the Sentence'}
        </h2>

        {qType === QuestionType.DEFINITION ? (
          <h1 className="text-4xl md:text-5xl font-black text-white mb-8 drop-shadow-md">
            {currentWord.word}
          </h1>
        ) : (
          <h1 className="text-2xl md:text-3xl font-bold text-white mb-8 leading-relaxed">
            "{currentWord.sentence}"
          </h1>
        )}

        {/* Options Grid */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 w-full">
          {options.map((opt, idx) => {
            let btnVariant: 'secondary' | 'success' | 'danger' = 'secondary';
            if (selectedAnswer === opt) {
              btnVariant = isCorrect ? 'success' : 'danger';
            } else if (selectedAnswer && !isCorrect) {
              // Highlight correct answer if wrong one picked
               if ((qType === QuestionType.DEFINITION && opt === currentWord.definition) ||
                   (qType === QuestionType.FILL_BLANK && opt === currentWord.word)) {
                   btnVariant = 'success';
               }
            }

            return (
              <Button
                key={idx}
                variant={btnVariant}
                onClick={() => handleAnswer(opt)}
                disabled={!!selectedAnswer}
                className="h-full min-h-[80px] text-lg normal-case"
              >
                {opt}
              </Button>
            );
          })}
        </div>

        {/* Feedback / Next */}
        {selectedAnswer && (
          <div className="mt-8 animate-in fade-in slide-in-from-bottom-4 duration-300 w-full">
            <div className={`p-4 rounded-xl mb-4 ${isCorrect ? 'bg-green-500/20 text-green-200' : 'bg-red-500/20 text-red-200'}`}>
              {isCorrect ? (
                <div className="flex items-center justify-center gap-2 font-bold text-xl">
                  <CheckCircle /> Critical Hit! Great job!
                </div>
              ) : (
                <div className="flex items-center justify-center gap-2 font-bold text-xl">
                  <XCircle /> Missed! The correct answer was: <br/>
                  {qType === QuestionType.DEFINITION ? currentWord.definition : currentWord.word}
                </div>
              )}
            </div>
            <Button size="lg" className="w-full" onClick={nextQuestion}>
              {currentIndex < gameWords.length - 1 ? 'Next Challenge' : 'Finish Battle'}
            </Button>
          </div>
        )}
      </div>
    </div>
  );
};

