            </div>

            {/* Main Dashboard Grid */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8 w-full max-w-4xl">

              {/* Left: Avatar & Stats */}
              <div className="bg-slate-800 rounded-3xl p-8 border-b-8 border-slate-950 flex flex-col items-center relative overflow-hidden">
                 {/* Bg glow */}
                 <div className="absolute top-0 w-full h-full bg-indigo-500/5 z-0 pointer-events-none"></div>

                 <div className="z-10 mb-6">
                    <AvatarDisplay user={user} size="lg" />
                 </div>

                 <div className="w-full z-10 space-y-3">
                    <h2 className="text-3xl font-bold text-center mb-1">{user.name}</h2>
