export enum GameScreen {
  HOME = 'HOME',
  ADVENTURE = 'ADVENTURE',
  SHOP = 'SHOP',
  INVENTORY = 'INVENTORY',
  PARENT_ZONE = 'PARENT_ZONE',
  BATTLE = 'BATTLE'
}

export enum QuestionType {
  DEFINITION = 'DEFINITION',
  FILL_BLANK = 'FILL_BLANK',
  SYNONYM = 'SYNONYM'
}

export interface VocabWord {
  id: string;
  word: string;
  definition: string;
  sentence: string; // Sentence with the word masked
  synonyms: string[];
  distractors: string[]; // Wrong definitions for multiple choice
  masteryLevel: number; // 0-100
}

export interface ShopItem {
  id: string;
  name: string;
  emoji: string;
  price: number;
  type: 'HEAD' | 'FACE' | 'HAND' | 'PET';
  description: string;
  bonus?: {
    type: 'GOLD' | 'XP';
    value: number; // Percentage, e.g. 10 for 10%
  };
}

export interface UserProfile {
  name: string;
  gold: number;
  xp: number;
  level: number;
  questsCompleted: number; // New field to track completed battles
  inventory: string[]; // list of item IDs
