                  <div className="relative z-10 flex items-center gap-3">
                    <Play fill="currentColor" size={32} /> Start Adventure
                  </div>
                </Button>

                <div className="grid grid-cols-2 gap-4">
                    <Button 
                        size="lg" 
                        variant="secondary"
                        className="w-full h-20 text-lg flex-col gap-1"
