import React, { useState, useEffect, useMemo } from 'react';
import { VocabWord, QuestionType, UserProfile } from '../types';
import { SHOP_ITEMS } from '../constants';
import { Button } from './ui/Button';
import { CheckCircle, XCircle, Trophy, Lightbulb, Shield, Sparkles, TrendingUp, Coins, Play } from 'lucide-react';
import confetti from 'canvas-confetti';
import { AvatarDisplay } from './AvatarDisplay';

interface BattleArenaProps {
  words: VocabWord[];
  user: UserProfile;
  onComplete: (score: number, goldEarned: number, xpEarned: number) => void;
  onExit: () => void;
}

type BattleStage = 'START' | 'BATTLE' | 'RESULTS';

export const BattleArena: React.FC<BattleArenaProps> = ({ words, user, onComplete, onExit }) => {
  const [stage, setStage] = useState<BattleStage>('START');
  const [currentIndex, setCurrentIndex] = useState(0);
  const [score, setScore] = useState(0);
  const [selectedAnswer, setSelectedAnswer] = useState<string | null>(null);
  const [isCorrect, setIsCorrect] = useState<boolean | null>(null);
  const [gameWords, setGameWords] = useState<VocabWord[]>([]);
  const [options, setOptions] = useState<string[]>([]);
  const [qType, setQType] = useState<QuestionType>(QuestionType.DEFINITION);
  const [activeSentence, setActiveSentence] = useState<string>('');
  const [synonymTarget, setSynonymTarget] = useState<'synonym' | 'antonym'>('synonym');
  const [hiddenOptions, setHiddenOptions] = useState<string[]>([]);

  // Power-up States
  const [hintsUsed, setHintsUsed] = useState(0);
  const [shieldsUsed, setShieldsUsed] = useState(0);

  // Calculate Gear Bonuses
  const bonuses = useMemo(() => {
    let gold = 0;
    let xp = 0;
    Object.values(user.equipped).forEach(itemId => {
      const item = SHOP_ITEMS.find(i => i.id === itemId);
      if (item?.bonus) {
        if (item.bonus.type === 'GOLD') gold += item.bonus.value;
        if (item.bonus.type === 'XP') xp += item.bonus.value;
      }
    });
    return { 
      gold, 
      xp,
      maxHints: Math.floor(xp / 10), // 1 hint per 10% XP bonus
      maxShields: Math.floor(gold / 10) // 1 shield per 10% Gold bonus
    };
  }, [user.equipped]);

  // Initialize game
  useEffect(() => {
    const shuffled = [...words].sort(() => 0.5 - Math.random());
    setGameWords(shuffled.slice(0, 10));
  }, [words]);

  // Setup options when index changes
  useEffect(() => {
    if (gameWords.length === 0 || stage !== 'BATTLE') return;

    const currentWord = gameWords[currentIndex];
    const types = [QuestionType.DEFINITION, QuestionType.FILL_BLANK, QuestionType.SYNONYM];
    const type = types[Math.floor(Math.random() * types.length)];
    setQType(type);

    let opts: string[] = [];

    if (type === QuestionType.DEFINITION) {
      opts = [currentWord.definition, ...currentWord.distractors];
    } else if (type === QuestionType.FILL_BLANK) {
      const randomSentence = currentWord.sentences[Math.floor(Math.random() * currentWord.sentences.length)];
      setActiveSentence(randomSentence);
      const otherWords = words
        .filter(w => w.id !== currentWord.id)
        .map(w => w.word)
        .sort(() => 0.5 - Math.random())
        .slice(0, 3);
      opts = [currentWord.word, ...otherWords];
    } else if (type === QuestionType.SYNONYM) {
      const mode = Math.random() > 0.5 ? 'synonym' : 'antonym';
      setSynonymTarget(mode);

      const correct = mode === 'synonym' ? currentWord.synonyms[0] : currentWord.antonyms[0];
      const decoys = words
        .filter(w => w.id !== currentWord.id)
        .flatMap(w => mode === 'synonym' ? w.synonyms : w.antonyms)
        .sort(() => 0.5 - Math.random())
        .slice(0, 3);
      opts = [correct, ...decoys];
    }

    setOptions(opts.sort(() => 0.5 - Math.random()));
    setSelectedAnswer(null);
    setIsCorrect(null);
    setHiddenOptions([]);
  }, [currentIndex, gameWords, words, stage]);

  const useHint = () => {
    if (hintsUsed >= bonuses.maxHints || selectedAnswer || qType === QuestionType.FILL_BLANK) return;

    const currentWord = gameWords[currentIndex];
    let correct = '';
    if (qType === QuestionType.DEFINITION) correct = currentWord.definition;
    if (qType === QuestionType.SYNONYM) correct = synonymTarget === 'synonym' ? currentWord.synonyms[0] : currentWord.antonyms[0];

    const wrongs = options.filter(o => o !== correct && !hiddenOptions.includes(o));
    const toHide = wrongs.sort(() => 0.5 - Math.random()).slice(0, 2);

    setHiddenOptions(prev => [...prev, ...toHide]);
    setHintsUsed(prev => prev + 1);
  };

  const handleAnswer = (ans: string) => {
    if (selectedAnswer) return;

    const currentWord = gameWords[currentIndex];
    let correct = false;

    if (qType === QuestionType.DEFINITION) correct = ans === currentWord.definition;
    else if (qType === QuestionType.FILL_BLANK) correct = ans === currentWord.word;
    else if (qType === QuestionType.SYNONYM) correct = synonymTarget === 'synonym' ? currentWord.synonyms.includes(ans) : currentWord.antonyms.includes(ans);

    if (!correct && (bonuses.maxShields - shieldsUsed) > 0) {
      setShieldsUsed(prev => prev + 1);
      // Visual feedback for shield use could be added here
      return; // Let them try again
    }

    setSelectedAnswer(ans);
    setIsCorrect(correct);

    if (correct) {
      confetti({ particleCount: 40, spread: 60, origin: { y: 0.7 } });
      setScore(s => s + 100);
    }
  };

  const nextQuestion = () => {
    if (currentIndex < gameWords.length - 1) {
      setCurrentIndex(prev => prev + 1);
    } else {
      setStage('RESULTS');
    }
  };

  const finalizeBattle = () => {
    const baseGold = Math.floor(score / 5);
    const baseXp = score;
    const goldBonus = Math.floor(baseGold * (bonuses.gold / 100));
    const xpBonus = Math.floor(baseXp * (bonuses.xp / 100));
    onComplete(score, baseGold + goldBonus, baseXp + xpBonus);
  };

  if (gameWords.length === 0) return <div className="p-10 text-center">Loading Battle...</div>;

  const currentWord = gameWords[currentIndex];
  const progress = ((currentIndex) / gameWords.length) * 100;

  // RENDER START SCREEN
  if (stage === 'START') {
    return (
      <div className="flex flex-col items-center justify-center p-6 max-w-2xl mx-auto w-full min-h-screen text-center animate-in zoom-in duration-300">
        <div className="mb-8">
          <AvatarDisplay user={user} size="lg" />
          <h2 className="text-4xl font-black mt-6 mb-2">Ready for Battle?</h2>
          <p className="text-slate-400">Your gear provides powerful bonuses!</p>
        </div>

        <div className="grid grid-cols-2 gap-4 w-full mb-8">
          <div className="bg-slate-800 p-4 rounded-2xl border-b-4 border-slate-950 flex flex-col items-center gap-2">
            <TrendingUp className="text-purple-400" />
            <span className="text-sm font-bold text-slate-400 uppercase">XP Boost</span>
            <span className="text-2xl font-black text-purple-400">+{bonuses.xp}%</span>
            <div className="flex gap-1 mt-1">
              {[...Array(bonuses.maxHints)].map((_, i) => <Lightbulb key={i} size={14} className="text-yellow-400 fill-yellow-400" />)}
              {bonuses.maxHints === 0 && <span className="text-[10px] text-slate-600">No Hints</span>}
            </div>
          </div>
          <div className="bg-slate-800 p-4 rounded-2xl border-b-4 border-slate-950 flex flex-col items-center gap-2">
            <Coins className="text-yellow-400" />
            <span className="text-sm font-bold text-slate-400 uppercase">Gold Boost</span>
            <span className="text-2xl font-black text-yellow-400">+{bonuses.gold}%</span>
            <div className="flex gap-1 mt-1">
              {[...Array(bonuses.maxShields)].map((_, i) => <Shield key={i} size={14} className="text-blue-400 fill-blue-400" />)}
              {bonuses.maxShields === 0 && <span className="text-[10px] text-slate-600">No Shields</span>}
            </div>
          </div>
        </div>

        <Button size="lg" className="w-full h-20 text-2xl" onClick={() => setStage('BATTLE')}>
          <Play fill="currentColor" /> Begin Quest
        </Button>
      </div>
    );
  }

  // RENDER RESULTS SCREEN
  if (stage === 'RESULTS') {
    const baseGold = Math.floor(score / 5);
    const baseXp = score;
    const goldBonus = Math.floor(baseGold * (bonuses.gold / 100));
    const xpBonus = Math.floor(baseXp * (bonuses.xp / 100));

    return (
      <div className="flex flex-col items-center justify-center p-6 max-w-2xl mx-auto w-full min-h-screen animate-in fade-in duration-500">
        <div className="bg-slate-800 rounded-3xl p-8 border-b-8 border-slate-950 w-full text-center relative overflow-hidden">
          <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-indigo-500 via-purple-500 to-pink-500"></div>

          <h2 className="text-5xl font-black text-white mb-2 mt-4">Victory!</h2>
          <p className="text-slate-400 mb-8 uppercase tracking-widest font-bold">Battle Results</p>

          <div className="space-y-4 mb-8">
            {/* XP Breakdown */}
            <div className="bg-slate-900 rounded-2xl p-6 border border-slate-700">
              <div className="flex justify-between items-center mb-2">
                <span className="text-slate-400 font-bold uppercase text-sm flex items-center gap-2"><Sparkles size={16}/> Experience gained</span>
                <span className="text-2xl font-black text-white">{baseXp + xpBonus} XP</span>
              </div>
              <div className="flex justify-between text-xs text-slate-500">
                <span>Base: {baseXp}</span>
                <span className="text-purple-400 font-bold">Gear Bonus (+{bonuses.xp}%): +{xpBonus}</span>
              </div>
            </div>

            {/* Gold Breakdown */}
            <div className="bg-slate-900 rounded-2xl p-6 border border-slate-700">
              <div className="flex justify-between items-center mb-2">
                <span className="text-slate-400 font-bold uppercase text-sm flex items-center gap-2"><Coins size={16}/> Gold earned</span>
                <span className="text-2xl font-black text-yellow-400">💰 {baseGold + goldBonus}</span>
              </div>
              <div className="flex justify-between text-xs text-slate-500">
                <span>Base: {baseGold}</span>
                <span className="text-yellow-600 font-bold">Gear Bonus (+{bonuses.gold}%): +{goldBonus}</span>
              </div>
            </div>
          </div>

          <Button size="lg" className="w-full h-16" onClick={finalizeBattle}>
            Collect Rewards
          </Button>
        </div>
      </div>
    );
  }

  // RENDER BATTLE SCREEN
  const getQuestionLabel = () => {
    switch(qType) {
      case QuestionType.DEFINITION: return 'Find the Definition';
      case QuestionType.FILL_BLANK: return 'Context Challenge';
      case QuestionType.SYNONYM: return synonymTarget === 'synonym' ? 'Find a Synonym' : 'Find an Antonym';
      default: return 'Challenge';
    }
  };

  const getCorrectText = () => {
    if (qType === QuestionType.DEFINITION) return currentWord.definition;
    if (qType === QuestionType.FILL_BLANK) return currentWord.word;
    return synonymTarget === 'synonym' ? currentWord.synonyms[0] : currentWord.antonyms[0];
  };

  return (
    <div className="flex flex-col flex-grow max-w-2xl mx-auto w-full p-4 min-h-[600px] justify-center animate-in fade-in duration-300">
      <div className="flex justify-between items-center mb-6">
        <Button size="sm" variant="secondary" onClick={onExit}>Exit</Button>

        <div className="flex gap-2">
          {/* Shields Indicator */}
          {bonuses.maxShields > 0 && (
            <div className="flex items-center gap-1 bg-blue-900/30 px-3 py-1.5 rounded-full border border-blue-500/50">
              <Shield className={`${shieldsUsed < bonuses.maxShields ? 'text-blue-400' : 'text-slate-600'} w-4 h-4`} fill="currentColor" />
              <span className="text-xs font-bold text-blue-200">{bonuses.maxShields - shieldsUsed}</span>
            </div>
          )}
          {/* Score Indicator */}
          <div className="flex items-center gap-2 bg-slate-800 px-4 py-2 rounded-full border border-slate-700">
            <Trophy className="text-yellow-400 w-5 h-5" />
            <span className="font-bold text-xl">{score}</span>
          </div>
        </div>
      </div>

      <div className="w-full bg-slate-700 h-3 rounded-full mb-8">
        <div 
          className="bg-indigo-500 h-3 rounded-full transition-all duration-300 shadow-[0_0_10px_rgba(99,102,241,0.5)]"
          style={{ width: `${progress}%` }}
        ></div>
      </div>

      <div className="bg-slate-800 rounded-3xl p-8 shadow-2xl border-b-8 border-slate-950 flex-grow flex flex-col items-center justify-center text-center relative overflow-hidden">
        <div className="absolute top-[-50px] right-[-50px] w-32 h-32 bg-indigo-500 rounded-full opacity-20 blur-xl"></div>
        <div className="absolute bottom-[-50px] left-[-50px] w-32 h-32 bg-purple-500 rounded-full opacity-20 blur-xl"></div>

        <div className="flex items-center justify-between w-full mb-6">
           <div className="flex items-center gap-2">
            <Lightbulb className="text-indigo-400 w-4 h-4" />
            <h2 className="text-gray-400 font-bold uppercase tracking-widest text-xs">
              {getQuestionLabel()}
            </h2>
          </div>

          {/* Hint Button */}
          {bonuses.maxHints > 0 && qType !== QuestionType.FILL_BLANK && (
            <button 
              onClick={useHint}
              disabled={hintsUsed >= bonuses.maxHints || !!selectedAnswer}
              className={`flex items-center gap-1 px-3 py-1 rounded-lg transition-all ${hintsUsed < bonuses.maxHints ? 'bg-yellow-500/20 text-yellow-400 hover:bg-yellow-500/30 active:scale-95 border border-yellow-500/30' : 'opacity-30 cursor-not-allowed text-slate-500'}`}
            >
              <Lightbulb size={14} fill={hintsUsed < bonuses.maxHints ? 'currentColor' : 'none'} />
              <span className="text-xs font-black">HINT ({bonuses.maxHints - hintsUsed})</span>
            </button>
          )}
        </div>

        {qType === QuestionType.DEFINITION ? (
          <h1 className="text-4xl md:text-5xl font-black text-white mb-8 drop-shadow-md">
            {currentWord.word}
          </h1>
        ) : qType === QuestionType.FILL_BLANK ? (
          <h1 className="text-xl md:text-2xl font-bold text-white mb-8 leading-relaxed italic">
            "{activeSentence}"
          </h1>
        ) : (
          <div className="mb-8">
            <p className="text-slate-400 mb-2 text-sm uppercase font-bold tracking-widest">Find a {synonymTarget} for:</p>
            <h1 className="text-4xl md:text-5xl font-black text-white drop-shadow-md">
              {currentWord.word}
            </h1>
          </div>
        )}

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 w-full">
          {options.map((opt, idx) => {
            const isHidden = hiddenOptions.includes(opt);
            let btnVariant: 'secondary' | 'success' | 'danger' = 'secondary';
            if (selectedAnswer === opt) {
              btnVariant = isCorrect ? 'success' : 'danger';
            } else if (selectedAnswer && !isCorrect) {
               if (opt === getCorrectText()) {
                   btnVariant = 'success';
               }
            }

            return (
              <Button
                key={idx}
                variant={btnVariant}
                onClick={() => handleAnswer(opt)}
                disabled={!!selectedAnswer || isHidden}
                className={`h-full min-h-[80px] text-lg normal-case transition-opacity duration-300 ${isHidden ? 'opacity-0 pointer-events-none' : 'opacity-100'}`}
              >
                {opt}
              </Button>
            );
          })}
        </div>

        {selectedAnswer && (
          <div className="mt-8 animate-in fade-in slide-in-from-bottom-4 duration-300 w-full">
            <div className={`p-4 rounded-xl mb-4 border-2 ${isCorrect ? 'bg-green-500/10 border-green-500/30 text-green-200' : 'bg-red-500/10 border-red-500/30 text-red-200'}`}>
              {isCorrect ? (
                <div className="flex items-center justify-center gap-2 font-bold text-xl">
                  <CheckCircle /> Level Up! Correct!
                </div>
              ) : (
                <div className="flex flex-col items-center justify-center gap-1 font-bold">
                  <div className="flex items-center gap-2 text-xl"><XCircle /> Not quite...</div>
                  <div className="text-sm opacity-80">The right answer was:</div>
                  <div className="text-lg text-white underline">{getCorrectText()}</div>
                </div>
              )}
            </div>
            <Button size="lg" className="w-full" onClick={nextQuestion}>
              {currentIndex < gameWords.length - 1 ? 'Next Question' : 'Finish Battle'}
            </Button>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { VocabWord, QuestionType, UserProfile } from '../types';
import { SHOP_ITEMS } from '../constants';
import { Button } from './ui/Button';
import { CheckCircle, XCircle, Trophy, Lightbulb, Shield, Sparkles, TrendingUp, Coins, Play } from 'lucide-react';
import confetti from 'canvas-confetti';
import { AvatarDisplay } from './AvatarDisplay';

interface BattleArenaProps {
  words: VocabWord[];
  user: UserProfile;
  onComplete: (score: number, goldEarned: number, xpEarned: number) => void;
  onExit: () => void;
}

type BattleStage = 'START' | 'BATTLE' | 'RESULTS';

export const BattleArena: React.FC<BattleArenaProps> = ({ words, user, onComplete, onExit }) => {
  const [stage, setStage] = useState<BattleStage>('START');
  const [currentIndex, setCurrentIndex] = useState(0);
  const [score, setScore] = useState(0);
  const [selectedAnswer, setSelectedAnswer] = useState<string | null>(null);
  const [isCorrect, setIsCorrect] = useState<boolean | null>(null);
  const [gameWords, setGameWords] = useState<VocabWord[]>([]);
  const [options, setOptions] = useState<string[]>([]);
  const [qType, setQType] = useState<QuestionType>(QuestionType.DEFINITION);
  const [activeSentence, setActiveSentence] = useState<string>('');
  const [synonymTarget, setSynonymTarget] = useState<'synonym' | 'antonym'>('synonym');
  const [hiddenOptions, setHiddenOptions] = useState<string[]>([]);

  // Power-up States
  const [hintsUsed, setHintsUsed] = useState(0);
  const [shieldsUsed, setShieldsUsed] = useState(0);

  // Calculate Gear Bonuses from equipped items
  const bonuses = useMemo(() => {
    let gold = 0;
    let xp = 0;
    Object.values(user.equipped).forEach(itemId => {
      const item = SHOP_ITEMS.find(i => i.id === itemId);
      if (item?.bonus) {
        if (item.bonus.type === 'GOLD') gold += item.bonus.value;
        if (item.bonus.type === 'XP') xp += item.bonus.value;
      }
    });
    return { 
      gold, 
      xp,
      maxHints: Math.floor(xp / 10), // 1 hint per 10% XP bonus
      maxShields: Math.floor(gold / 10) // 1 shield per 10% Gold bonus
    };
  }, [user.equipped]);

  // Initialize game
  useEffect(() => {
    const shuffled = [...words].sort(() => 0.5 - Math.random());
    setGameWords(shuffled.slice(0, 10));
  }, [words]);

  // Setup options when index changes
  useEffect(() => {
    if (gameWords.length === 0 || stage !== 'BATTLE') return;

    const currentWord = gameWords[currentIndex];
    const types = [QuestionType.DEFINITION, QuestionType.FILL_BLANK, QuestionType.SYNONYM];
    const type = types[Math.floor(Math.random() * types.length)];
    setQType(type);

    let opts: string[] = [];

    if (type === QuestionType.DEFINITION) {
      opts = [currentWord.definition, ...currentWord.distractors];
    } else if (type === QuestionType.FILL_BLANK) {
      const randomSentence = currentWord.sentences[Math.floor(Math.random() * currentWord.sentences.length)];
      setActiveSentence(randomSentence);
      const otherWords = words
        .filter(w => w.id !== currentWord.id)
        .map(w => w.word)
        .sort(() => 0.5 - Math.random())
        .slice(0, 3);
      opts = [currentWord.word, ...otherWords];
    } else if (type === QuestionType.SYNONYM) {
      const mode = Math.random() > 0.5 ? 'synonym' : 'antonym';
      setSynonymTarget(mode);

      const correct = mode === 'synonym' ? currentWord.synonyms[0] : currentWord.antonyms[0];
      const decoys = words
        .filter(w => w.id !== currentWord.id)
        .flatMap(w => mode === 'synonym' ? w.synonyms : w.antonyms)
        .sort(() => 0.5 - Math.random())
        .slice(0, 3);
      opts = [correct, ...decoys];
    }

    setOptions(opts.sort(() => 0.5 - Math.random()));
    setSelectedAnswer(null);
    setIsCorrect(null);
    setHiddenOptions([]);
  }, [currentIndex, gameWords, words, stage]);

  const useHint = () => {
    if (hintsUsed >= bonuses.maxHints || selectedAnswer || qType === QuestionType.FILL_BLANK) return;

    const currentWord = gameWords[currentIndex];
    let correct = '';
    if (qType === QuestionType.DEFINITION) correct = currentWord.definition;
    if (qType === QuestionType.SYNONYM) correct = synonymTarget === 'synonym' ? currentWord.synonyms[0] : currentWord.antonyms[0];

    const wrongs = options.filter(o => o !== correct && !hiddenOptions.includes(o));
    const toHide = wrongs.sort(() => 0.5 - Math.random()).slice(0, 2);

    setHiddenOptions(prev => [...prev, ...toHide]);
    setHintsUsed(prev => prev + 1);
  };

  const handleAnswer = (ans: string) => {
    if (selectedAnswer) return;

    const currentWord = gameWords[currentIndex];
    let correct = false;

    if (qType === QuestionType.DEFINITION) correct = ans === currentWord.definition;
    else if (qType === QuestionType.FILL_BLANK) correct = ans === currentWord.word;
    else if (qType === QuestionType.SYNONYM) correct = synonymTarget === 'synonym' ? currentWord.synonyms.includes(ans) : currentWord.antonyms.includes(ans);

    // If answer is wrong but user has shields, use one and let them try again
    if (!correct && (bonuses.maxShields - shieldsUsed) > 0) {
      setShieldsUsed(prev => prev + 1);
      // Trigger a visual "Shield" effect here if needed
      return; 
    }

    setSelectedAnswer(ans);
    setIsCorrect(correct);

    if (correct) {
      confetti({ particleCount: 40, spread: 60, origin: { y: 0.7 } });
      setScore(s => s + 100);
    }
  };

  const nextQuestion = () => {
    if (currentIndex < gameWords.length - 1) {
      setCurrentIndex(prev => prev + 1);
    } else {
      setStage('RESULTS');
    }
  };

  const finalizeBattle = () => {
    // 1 Score Point = 1 Base Gold and 1 Base XP
    const baseReward = score; 
    const goldBonus = Math.floor(baseReward * (bonuses.gold / 100));
    const xpBonus = Math.floor(baseReward * (bonuses.xp / 100));

    onComplete(score, baseReward + goldBonus, baseReward + xpBonus);
  };

  if (gameWords.length === 0) return <div className="p-10 text-center">Loading Battle...</div>;

  const currentWord = gameWords[currentIndex];
  const progress = ((currentIndex) / gameWords.length) * 100;

  // RENDER START SCREEN
  if (stage === 'START') {
    return (
      <div className="flex flex-col items-center justify-center p-6 max-w-2xl mx-auto w-full min-h-screen text-center animate-in zoom-in duration-300">
        <div className="mb-8">
          <AvatarDisplay user={user} size="lg" />
          <h2 className="text-4xl font-black mt-6 mb-2">Ready for Battle?</h2>
          <p className="text-slate-400">Your gear provides powerful bonuses!</p>
        </div>

        <div className="grid grid-cols-2 gap-4 w-full mb-8">
          <div className="bg-slate-800 p-4 rounded-2xl border-b-4 border-slate-950 flex flex-col items-center gap-2">
            <TrendingUp className="text-purple-400" />
            <span className="text-sm font-bold text-slate-400 uppercase">XP Boost</span>
            <span className="text-2xl font-black text-purple-400">+{bonuses.xp}%</span>
            <div className="flex gap-1 mt-1">
              {[...Array(bonuses.maxHints)].map((_, i) => <Lightbulb key={i} size={14} className="text-yellow-400 fill-yellow-400" />)}
              {bonuses.maxHints === 0 && <span className="text-[10px] text-slate-600 italic">No Hints</span>}
            </div>
          </div>
          <div className="bg-slate-800 p-4 rounded-2xl border-b-4 border-slate-950 flex flex-col items-center gap-2">
            <Coins className="text-yellow-400" />
            <span className="text-sm font-bold text-slate-400 uppercase">Gold Boost</span>
            <span className="text-2xl font-black text-yellow-400">+{bonuses.gold}%</span>
            <div className="flex gap-1 mt-1">
              {[...Array(bonuses.maxShields)].map((_, i) => <Shield key={i} size={14} className="text-blue-400 fill-blue-400" />)}
              {bonuses.maxShields === 0 && <span className="text-[10px] text-slate-600 italic">No Shields</span>}
            </div>
          </div>
        </div>

        <Button size="lg" className="w-full h-20 text-2xl" onClick={() => setStage('BATTLE')}>
          <Play fill="currentColor" /> Begin Quest
        </Button>
      </div>
    );
  }

  // RENDER RESULTS SCREEN
  if (stage === 'RESULTS') {
    const baseReward = score;
    const goldBonus = Math.floor(baseReward * (bonuses.gold / 100));
    const xpBonus = Math.floor(baseReward * (bonuses.xp / 100));

    return (
      <div className="flex flex-col items-center justify-center p-6 max-w-2xl mx-auto w-full min-h-screen animate-in fade-in duration-500">
        <div className="bg-slate-800 rounded-3xl p-8 border-b-8 border-slate-950 w-full text-center relative overflow-hidden">
          <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-indigo-500 via-purple-500 to-pink-500"></div>

          <h2 className="text-5xl font-black text-white mb-2 mt-4">Victory!</h2>
          <p className="text-slate-400 mb-8 uppercase tracking-widest font-bold">Battle Results</p>

          <div className="space-y-4 mb-8">
            {/* XP Breakdown */}
            <div className="bg-slate-900 rounded-2xl p-6 border border-slate-700">
              <div className="flex justify-between items-center mb-2">
                <span className="text-slate-400 font-bold uppercase text-sm flex items-center gap-2"><Sparkles size={16}/> Experience gained</span>
                <span className="text-2xl font-black text-white">{baseReward + xpBonus} XP</span>
              </div>
              <div className="flex justify-between text-xs text-slate-500">
                <span>Base: {baseReward}</span>
                <span className="text-purple-400 font-bold">Gear Bonus (+{bonuses.xp}%): +{xpBonus}</span>
              </div>
            </div>

            {/* Gold Breakdown */}
            <div className="bg-slate-900 rounded-2xl p-6 border border-slate-700">
              <div className="flex justify-between items-center mb-2">
                <span className="text-slate-400 font-bold uppercase text-sm flex items-center gap-2"><Coins size={16}/> Gold earned</span>
                <span className="text-2xl font-black text-yellow-400">💰 {baseReward + goldBonus}</span>
              </div>
              <div className="flex justify-between text-xs text-slate-500">
                <span>Base: {baseReward}</span>
                <span className="text-yellow-600 font-bold">Gear Bonus (+{bonuses.gold}%): +{goldBonus}</span>
              </div>
            </div>
          </div>

          <Button size="lg" className="w-full h-16" onClick={finalizeBattle}>
            Collect Rewards
          </Button>
        </div>
      </div>
    );
  }

  // RENDER BATTLE SCREEN
  const getQuestionLabel = () => {
    switch(qType) {
      case QuestionType.DEFINITION: return 'Find the Definition';
      case QuestionType.FILL_BLANK: return 'Context Challenge';
      case QuestionType.SYNONYM: return synonymTarget === 'synonym' ? 'Find a Synonym' : 'Find an Antonym';
      default: return 'Challenge';
    }
  };

  const getCorrectText = () => {
    if (qType === QuestionType.DEFINITION) return currentWord.definition;
    if (qType === QuestionType.FILL_BLANK) return currentWord.word;
    return synonymTarget === 'synonym' ? currentWord.synonyms[0] : currentWord.antonyms[0];
  };

  return (
    <div className="flex flex-col flex-grow max-w-2xl mx-auto w-full p-4 min-h-[600px] justify-center animate-in fade-in duration-300">
      <div className="flex justify-between items-center mb-6">
        <Button size="sm" variant="secondary" onClick={onExit}>Exit</Button>

        <div className="flex gap-2">
          {/* Shields Indicator */}
          {bonuses.maxShields > 0 && (
            <div className="flex items-center gap-1 bg-blue-900/30 px-3 py-1.5 rounded-full border border-blue-500/50">
              <Shield className={`${shieldsUsed < bonuses.maxShields ? 'text-blue-400' : 'text-slate-600'} w-4 h-4`} fill="currentColor" />
              <span className="text-xs font-bold text-blue-200">{bonuses.maxShields - shieldsUsed}</span>
            </div>
          )}
          {/* Score Indicator */}
          <div className="flex items-center gap-2 bg-slate-800 px-4 py-2 rounded-full border border-slate-700">
            <Trophy className="text-yellow-400 w-5 h-5" />
            <span className="font-bold text-xl">{score}</span>
          </div>
        </div>
      </div>

      <div className="w-full bg-slate-700 h-3 rounded-full mb-8">
        <div 
          className="bg-indigo-500 h-3 rounded-full transition-all duration-300 shadow-[0_0_10px_rgba(99,102,241,0.5)]"
          style={{ width: `${progress}%` }}
        ></div>
      </div>

      <div className="bg-slate-800 rounded-3xl p-8 shadow-2xl border-b-8 border-slate-950 flex-grow flex flex-col items-center justify-center text-center relative overflow-hidden">
        <div className="absolute top-[-50px] right-[-50px] w-32 h-32 bg-indigo-500 rounded-full opacity-20 blur-xl"></div>
        <div className="absolute bottom-[-50px] left-[-50px] w-32 h-32 bg-purple-500 rounded-full opacity-20 blur-xl"></div>

        <div className="flex items-center justify-between w-full mb-6">
           <div className="flex items-center gap-2">
            <Lightbulb className="text-indigo-400 w-4 h-4" />
            <h2 className="text-gray-400 font-bold uppercase tracking-widest text-xs">
              {getQuestionLabel()}
            </h2>
          </div>

          {/* Hint Button */}
          {bonuses.maxHints > 0 && qType !== QuestionType.FILL_BLANK && (
            <button 
              onClick={useHint}
              disabled={hintsUsed >= bonuses.maxHints || !!selectedAnswer}
              className={`flex items-center gap-1 px-3 py-1 rounded-lg transition-all ${hintsUsed < bonuses.maxHints ? 'bg-yellow-500/20 text-yellow-400 hover:bg-yellow-500/30 active:scale-95 border border-yellow-500/30' : 'opacity-30 cursor-not-allowed text-slate-500'}`}
            >
              <Lightbulb size={14} fill={hintsUsed < bonuses.maxHints ? 'currentColor' : 'none'} />
              <span className="text-xs font-black">HINT ({bonuses.maxHints - hintsUsed})</span>
            </button>
          )}
        </div>

        {qType === QuestionType.DEFINITION ? (
          <h1 className="text-4xl md:text-5xl font-black text-white mb-8 drop-shadow-md">
            {currentWord.word}
          </h1>
        ) : qType === QuestionType.FILL_BLANK ? (
          <h1 className="text-xl md:text-2xl font-bold text-white mb-8 leading-relaxed italic">
            "{activeSentence}"
          </h1>
        ) : (
          <div className="mb-8">
            <p className="text-slate-400 mb-2 text-sm uppercase font-bold tracking-widest">Find a {synonymTarget} for:</p>
            <h1 className="text-4xl md:text-5xl font-black text-white drop-shadow-md">
              {currentWord.word}
            </h1>
          </div>
        )}

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 w-full">
          {options.map((opt, idx) => {
            const isHidden = hiddenOptions.includes(opt);
            let btnVariant: 'secondary' | 'success' | 'danger' = 'secondary';
            if (selectedAnswer === opt) {
              btnVariant = isCorrect ? 'success' : 'danger';
            } else if (selectedAnswer && !isCorrect) {
               if (opt === getCorrectText()) {
                   btnVariant = 'success';
               }
            }

            return (
              <Button
                key={idx}
                variant={btnVariant}
                onClick={() => handleAnswer(opt)}
                disabled={!!selectedAnswer || isHidden}
                className={`h-full min-h-[80px] text-lg normal-case transition-opacity duration-300 ${isHidden ? 'opacity-0 pointer-events-none' : 'opacity-100'}`}
              >
                {opt}
              </Button>
            );
          })}
        </div>

        {selectedAnswer && (
          <div className="mt-8 animate-in fade-in slide-in-from-bottom-4 duration-300 w-full">
            <div className={`p-4 rounded-xl mb-4 border-2 ${isCorrect ? 'bg-green-500/10 border-green-500/30 text-green-200' : 'bg-red-500/10 border-red-500/30 text-red-200'}`}>
              {isCorrect ? (
                <div className="flex items-center justify-center gap-2 font-bold text-xl">
                  <CheckCircle /> Level Up! Correct!
                </div>
              ) : (
                <div className="flex flex-col items-center justify-center gap-1 font-bold">
                  <div className="flex items-center gap-2 text-xl"><XCircle /> Not quite...</div>
                  <div className="text-sm opacity-80">The right answer was:</div>
                  <div className="text-lg text-white underline">{getCorrectText()}</div>
                </div>
              )}
            </div>
            <Button size="lg" className="w-full" onClick={nextQuestion}>
              {currentIndex < gameWords.length - 1 ? 'Next Question' : 'Finish Battle'}
            </Button>
          </div>
        )}
      </div>
    </div>
  );
};

export enum GameScreen {
  HOME = 'HOME',
  ADVENTURE = 'ADVENTURE',
  SHOP = 'SHOP',
  INVENTORY = 'INVENTORY',
  PARENT_ZONE = 'PARENT_ZONE',
  BATTLE = 'BATTLE'
}

export enum QuestionType {
  DEFINITION = 'DEFINITION',
  FILL_BLANK = 'FILL_BLANK',
  SYNONYM = 'SYNONYM'
}

export interface VocabWord {
  id: string;
  word: string;
  definition: string;
  sentences: string[];
  synonyms: string[];
  antonyms: string[];
  distractors: string[];
  masteryLevel: number;
}

export interface ShopItem {
  id: string;
  name: string;
  emoji: string;
  price: number;
  type: 'HEAD' | 'FACE' | 'HAND' | 'PET';
  description: string;
  bonus?: {
    type: 'GOLD' | 'XP' | 'SHIELD' | 'HINT';
    value: number; // Percentage for GOLD/XP, absolute count for SHIELD/HINT
  };
}

export interface UserProfile {
  name: string;
  gold: number;
  xp: number;
  level: number;
  questsCompleted: number;
  inventory: string[];
  equipped: {
    HEAD?: string;
    FACE?: string;
    HAND?: string;
    PET?: string;
  };
}

export interface GameState {
  currentScreen: GameScreen;
  words: VocabWord[];
  user: UserProfile;
  lastScore: number | null;
}

import React, { useState, useEffect, useMemo } from 'react';
import { VocabWord, QuestionType, UserProfile } from '../types';
import { SHOP_ITEMS } from '../constants';
import { Button } from './ui/Button';
import { CheckCircle, XCircle, Trophy, Lightbulb, Shield, Sparkles, TrendingUp, Coins, Play } from 'lucide-react';
import confetti from 'canvas-confetti';
import { AvatarDisplay } from './AvatarDisplay';

interface BattleArenaProps {
  words: VocabWord[];
  user: UserProfile;
  onComplete: (score: number, goldEarned: number, xpEarned: number) => void;
  onExit: () => void;
}

type BattleStage = 'START' | 'BATTLE' | 'RESULTS';

export const BattleArena: React.FC<BattleArenaProps> = ({ words, user, onComplete, onExit }) => {
  const [stage, setStage] = useState<BattleStage>('START');
  const [currentIndex, setCurrentIndex] = useState(0);
  const [score, setScore] = useState(0);
  const [goldEarned, setGoldEarned] = useState(0);
  const [selectedAnswer, setSelectedAnswer] = useState<string | null>(null);
  const [isCorrect, setIsCorrect] = useState<boolean | null>(null);
  const [gameWords, setGameWords] = useState<VocabWord[]>([]);
  const [options, setOptions] = useState<string[]>([]);
  const [qType, setQType] = useState<QuestionType>(QuestionType.DEFINITION);
  const [activeSentence, setActiveSentence] = useState<string>('');
  const [synonymTarget, setSynonymTarget] = useState<'synonym' | 'antonym'>('synonym');
  const [hiddenOptions, setHiddenOptions] = useState<string[]>([]);

  // Power-up States
  const [hintsUsed, setHintsUsed] = useState(0);
  const [shieldsUsed, setShieldsUsed] = useState(0);

  // Calculate Gear Bonuses from equipped items
  const bonuses = useMemo(() => {
    let goldBoost = 0;
    let xpBoost = 0;
    let totalShields = 0;
    let totalHints = 0;

    Object.values(user.equipped).forEach(itemId => {
      const item = SHOP_ITEMS.find(i => i.id === itemId);
      if (item?.bonus) {
        if (item.bonus.type === 'GOLD') goldBoost += item.bonus.value;
        if (item.bonus.type === 'XP') xpBoost += item.bonus.value;
        if (item.bonus.type === 'SHIELD') totalShields += item.bonus.value;
        if (item.bonus.type === 'HINT') totalHints += item.bonus.value;
      }
    });

    return { 
      goldBoost, 
      xpBoost,
      maxHints: totalHints,
      maxShields: totalShields
    };
  }, [user.equipped]);

  // Initialize game
  useEffect(() => {
    const shuffled = [...words].sort(() => 0.5 - Math.random());
    setGameWords(shuffled.slice(0, 10));
  }, [words]);

  // Setup options when index changes
  useEffect(() => {
    if (gameWords.length === 0 || stage !== 'BATTLE') return;

    const currentWord = gameWords[currentIndex];
    const types = [QuestionType.DEFINITION, QuestionType.FILL_BLANK, QuestionType.SYNONYM];
    const type = types[Math.floor(Math.random() * types.length)];
    setQType(type);

    let opts: string[] = [];

    if (type === QuestionType.DEFINITION) {
      opts = [currentWord.definition, ...currentWord.distractors];
    } else if (type === QuestionType.FILL_BLANK) {
      const randomSentence = currentWord.sentences[Math.floor(Math.random() * currentWord.sentences.length)];
      setActiveSentence(randomSentence);
      const otherWords = words
        .filter(w => w.id !== currentWord.id)
        .map(w => w.word)
        .sort(() => 0.5 - Math.random())
        .slice(0, 3);
      opts = [currentWord.word, ...otherWords];
    } else if (type === QuestionType.SYNONYM) {
      const mode = Math.random() > 0.5 ? 'synonym' : 'antonym';
      setSynonymTarget(mode);

      const correct = mode === 'synonym' ? currentWord.synonyms[0] : currentWord.antonyms[0];
      const decoys = words
        .filter(w => w.id !== currentWord.id)
        .flatMap(w => mode === 'synonym' ? w.synonyms : w.antonyms)
        .sort(() => 0.5 - Math.random())
        .slice(0, 3);
      opts = [correct, ...decoys];
    }

    setOptions(opts.sort(() => 0.5 - Math.random()));
    setSelectedAnswer(null);
    setIsCorrect(null);
    setHiddenOptions([]);
  }, [currentIndex, gameWords, words, stage]);

  const useHint = () => {
    if (hintsUsed >= bonuses.maxHints || selectedAnswer || qType === QuestionType.FILL_BLANK) return;

    const currentWord = gameWords[currentIndex];
    let correct = '';
    if (qType === QuestionType.DEFINITION) correct = currentWord.definition;
    if (qType === QuestionType.SYNONYM) correct = synonymTarget === 'synonym' ? currentWord.synonyms[0] : currentWord.antonyms[0];

    const wrongs = options.filter(o => o !== correct && !hiddenOptions.includes(o));
    const toHide = wrongs.sort(() => 0.5 - Math.random()).slice(0, 2);

    setHiddenOptions(prev => [...prev, ...toHide]);
    setHintsUsed(prev => prev + 1);
  };

  const handleAnswer = (ans: string) => {
    if (selectedAnswer) return;

    const currentWord = gameWords[currentIndex];
    let correct = false;

    if (qType === QuestionType.DEFINITION) correct = ans === currentWord.definition;
    else if (qType === QuestionType.FILL_BLANK) correct = ans === currentWord.word;
    else if (qType === QuestionType.SYNONYM) correct = synonymTarget === 'synonym' ? currentWord.synonyms.includes(ans) : currentWord.antonyms.includes(ans);

    if (!correct && (bonuses.maxShields - shieldsUsed) > 0) {
      setShieldsUsed(prev => prev + 1);
      return; 
    }

    setSelectedAnswer(ans);
    setIsCorrect(correct);

    if (correct) {
      confetti({ particleCount: 40, spread: 60, origin: { y: 0.7 } });
      const basePoints = 100;
      const boostValue = Math.floor(basePoints * (bonuses.goldBoost / 100));
      setScore(s => s + basePoints);
      setGoldEarned(g => g + basePoints + boostValue);
    }
  };

  const nextQuestion = () => {
    if (currentIndex < gameWords.length - 1) {
      setCurrentIndex(prev => prev + 1);
    } else {
      setStage('RESULTS');
    }
  };

  const finalizeBattle = () => {
    const basePoints = score; 
    const xpBonus = Math.floor(basePoints * (bonuses.xpBoost / 100));
    onComplete(score, goldEarned, basePoints + xpBonus);
  };

  if (gameWords.length === 0) return <div className="p-10 text-center">Loading Battle...</div>;

  const currentWord = gameWords[currentIndex];
  const progress = ((currentIndex) / gameWords.length) * 100;

  // RENDER START SCREEN
  if (stage === 'START') {
    return (
      <div className="flex flex-col items-center justify-center p-6 max-w-2xl mx-auto w-full min-h-screen text-center animate-in zoom-in duration-300">
        <div className="mb-8">
          <AvatarDisplay user={user} size="lg" />
          <h2 className="text-4xl font-black mt-6 mb-2">Ready for Battle?</h2>
          <p className="text-slate-400">Review your equipped gear bonuses!</p>
        </div>

        <div className="grid grid-cols-2 gap-4 w-full mb-8">
          <div className="bg-slate-800 p-4 rounded-2xl border-b-4 border-slate-950 flex flex-col items-center gap-2">
            <Coins className="text-yellow-400" />
            <span className="text-xs font-bold text-slate-400 uppercase">Gold Boost</span>
            <span className="text-2xl font-black text-yellow-400">+{bonuses.goldBoost}%</span>
          </div>
          <div className="bg-slate-800 p-4 rounded-2xl border-b-4 border-slate-950 flex flex-col items-center gap-2">
            <TrendingUp className="text-purple-400" />
            <span className="text-xs font-bold text-slate-400 uppercase">XP Boost</span>
            <span className="text-2xl font-black text-purple-400">+{bonuses.xpBoost}%</span>
          </div>
          <div className="bg-slate-800 p-4 rounded-2xl border-b-4 border-slate-950 flex flex-col items-center gap-2">
            <Shield className="text-blue-400" />
            <span className="text-xs font-bold text-slate-400 uppercase">Shields</span>
            <span className="text-2xl font-black text-blue-400">{bonuses.maxShields}</span>
          </div>
          <div className="bg-slate-800 p-4 rounded-2xl border-b-4 border-slate-950 flex flex-col items-center gap-2">
            <Lightbulb className="text-yellow-400" />
            <span className="text-xs font-bold text-slate-400 uppercase">Hints</span>
            <span className="text-2xl font-black text-yellow-400">{bonuses.maxHints}</span>
          </div>
        </div>

        <Button size="lg" className="w-full h-20 text-2xl" onClick={() => setStage('BATTLE')}>
          <Play fill="currentColor" /> Start Adventure
        </Button>
      </div>
    );
  }

  // RENDER RESULTS SCREEN
  if (stage === 'RESULTS') {
    const basePoints = score;
    const goldBonusTotal = goldEarned - basePoints;
    const xpBonusTotal = Math.floor(basePoints * (bonuses.xpBoost / 100));

    return (
      <div className="flex flex-col items-center justify-center p-6 max-w-2xl mx-auto w-full min-h-screen animate-in fade-in duration-500">
        <div className="bg-slate-800 rounded-3xl p-8 border-b-8 border-slate-950 w-full text-center relative overflow-hidden">
          <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-indigo-500 via-purple-500 to-pink-500"></div>

          <h2 className="text-5xl font-black text-white mb-2 mt-4">Victory!</h2>
          <p className="text-slate-400 mb-8 uppercase tracking-widest font-bold">Loot Collected</p>

          <div className="space-y-4 mb-8">
            <div className="bg-slate-900 rounded-2xl p-6 border border-slate-700">
              <div className="flex justify-between items-center mb-2">
                <span className="text-slate-400 font-bold uppercase text-sm flex items-center gap-2"><Coins size={16}/> Total Gold</span>
                <span className="text-2xl font-black text-yellow-400">💰 {goldEarned}</span>
              </div>
              <div className="flex justify-between text-xs text-slate-500">
                <span>Base Rewards: {basePoints}</span>
                <span className="text-yellow-600 font-bold">Gear Boost (+{bonuses.goldBoost}%): +{goldBonusTotal}</span>
              </div>
            </div>

            <div className="bg-slate-900 rounded-2xl p-6 border border-slate-700">
              <div className="flex justify-between items-center mb-2">
                <span className="text-slate-400 font-bold uppercase text-sm flex items-center gap-2"><Sparkles size={16}/> Total XP</span>
                <span className="text-2xl font-black text-white">{basePoints + xpBonusTotal} XP</span>
              </div>
              <div className="flex justify-between text-xs text-slate-500">
                <span>Base Rewards: {basePoints}</span>
                <span className="text-purple-400 font-bold">Gear Boost (+{bonuses.xpBoost}%): +{xpBonusTotal}</span>
              </div>
            </div>
          </div>

          <Button size="lg" className="w-full h-16" onClick={finalizeBattle}>
            Back to Home
          </Button>
        </div>
      </div>
    );
  }

  const getQuestionLabel = () => {
    switch(qType) {
      case QuestionType.DEFINITION: return 'Find the Definition';
      case QuestionType.FILL_BLANK: return 'Context Challenge';
      case QuestionType.SYNONYM: return synonymTarget === 'synonym' ? 'Find a Synonym' : 'Find an Antonym';
      default: return 'Challenge';
    }
  };

  const getCorrectText = () => {
    if (qType === QuestionType.DEFINITION) return currentWord.definition;
    if (qType === QuestionType.FILL_BLANK) return currentWord.word;
    return synonymTarget === 'synonym' ? currentWord.synonyms[0] : currentWord.antonyms[0];
  };

  return (
    <div className="flex flex-col flex-grow max-w-2xl mx-auto w-full p-4 min-h-[600px] justify-center animate-in fade-in duration-300">
      <div className="flex justify-between items-center mb-6">
        <Button size="sm" variant="secondary" onClick={onExit}>Exit</Button>

        <div className="flex gap-2">
          {/* Gold Counter */}
          <div className="flex items-center gap-2 bg-slate-800 px-4 py-2 rounded-full border border-yellow-500/30">
            <Coins className="text-yellow-400 w-4 h-4" />
            <span className="font-black text-yellow-400">{goldEarned}</span>
          </div>

          {/* Shields Indicator */}
          {bonuses.maxShields > 0 && (
            <div className="flex items-center gap-1 bg-blue-900/30 px-3 py-1.5 rounded-full border border-blue-500/50">
              <Shield className={`${shieldsUsed < bonuses.maxShields ? 'text-blue-400' : 'text-slate-600'} w-4 h-4`} fill="currentColor" />
              <span className="text-xs font-bold text-blue-200">{bonuses.maxShields - shieldsUsed}</span>
            </div>
          )}

          {/* Score Indicator */}
          <div className="flex items-center gap-2 bg-slate-800 px-4 py-2 rounded-full border border-slate-700">
            <Trophy className="text-white w-4 h-4" />
            <span className="font-bold text-lg">{score}</span>
          </div>
        </div>
      </div>

      <div className="w-full bg-slate-700 h-3 rounded-full mb-8">
        <div 
          className="bg-indigo-500 h-3 rounded-full transition-all duration-300 shadow-[0_0_10px_rgba(99,102,241,0.5)]"
          style={{ width: `${progress}%` }}
        ></div>
      </div>

      <div className="bg-slate-800 rounded-3xl p-8 shadow-2xl border-b-8 border-slate-950 flex-grow flex flex-col items-center justify-center text-center relative overflow-hidden">
        <div className="absolute top-[-50px] right-[-50px] w-32 h-32 bg-indigo-500 rounded-full opacity-10 blur-xl"></div>
        <div className="absolute bottom-[-50px] left-[-50px] w-32 h-32 bg-purple-500 rounded-full opacity-10 blur-xl"></div>

        <div className="flex items-center justify-between w-full mb-6">
           <div className="flex items-center gap-2">
            <Lightbulb className="text-indigo-400 w-4 h-4" />
            <h2 className="text-gray-400 font-bold uppercase tracking-widest text-xs">
              {getQuestionLabel()}
            </h2>
          </div>

          {/* Hint Button */}
          {bonuses.maxHints > 0 && qType !== QuestionType.FILL_BLANK && (
            <button 
              onClick={useHint}
              disabled={hintsUsed >= bonuses.maxHints || !!selectedAnswer}
              className={`flex items-center gap-1 px-3 py-1 rounded-lg transition-all ${hintsUsed < bonuses.maxHints ? 'bg-yellow-500/20 text-yellow-400 hover:bg-yellow-500/30 active:scale-95 border border-yellow-500/30' : 'opacity-30 cursor-not-allowed text-slate-500'}`}
            >
              <Lightbulb size={14} fill={hintsUsed < bonuses.maxHints ? 'currentColor' : 'none'} />
              <span className="text-xs font-black">HINT ({bonuses.maxHints - hintsUsed})</span>
            </button>
          )}
        </div>

        {qType === QuestionType.DEFINITION ? (
          <h1 className="text-4xl md:text-5xl font-black text-white mb-8 drop-shadow-md">
            {currentWord.word}
          </h1>
        ) : qType === QuestionType.FILL_BLANK ? (
          <h1 className="text-xl md:text-2xl font-bold text-white mb-8 leading-relaxed italic">
            "{activeSentence}"
          </h1>
        ) : (
          <div className="mb-8">
            <p className="text-slate-400 mb-2 text-sm uppercase font-bold tracking-widest">Identify a {synonymTarget} for:</p>
            <h1 className="text-4xl md:text-5xl font-black text-white drop-shadow-md">
              {currentWord.word}
            </h1>
          </div>
        )}

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 w-full">
          {options.map((opt, idx) => {
            const isHidden = hiddenOptions.includes(opt);
            let btnVariant: 'secondary' | 'success' | 'danger' = 'secondary';
            if (selectedAnswer === opt) {
              btnVariant = isCorrect ? 'success' : 'danger';
            } else if (selectedAnswer && !isCorrect) {
               if (opt === getCorrectText()) {
                   btnVariant = 'success';
               }
            }

            return (
              <Button
                key={idx}
                variant={btnVariant}
                onClick={() => handleAnswer(opt)}
                disabled={!!selectedAnswer || isHidden}
                className={`h-full min-h-[80px] text-lg normal-case transition-opacity duration-300 ${isHidden ? 'opacity-0 pointer-events-none' : 'opacity-100'}`}
              >
                {opt}
              </Button>
            );
          })}
        </div>

        {selectedAnswer && (
          <div className="mt-8 animate-in fade-in slide-in-from-bottom-4 duration-300 w-full">
            <div className={`p-4 rounded-xl mb-4 border-2 ${isCorrect ? 'bg-green-500/10 border-green-500/30 text-green-200' : 'bg-red-500/10 border-red-500/30 text-red-200'}`}>
              {isCorrect ? (
                <div className="flex items-center justify-center gap-2 font-bold text-xl">
                  <CheckCircle /> Level Up! Correct!
                </div>
              ) : (
                <div className="flex flex-col items-center justify-center gap-1 font-bold">
                  <div className="flex items-center gap-2 text-xl"><XCircle /> Not quite...</div>
                  <div className="text-sm opacity-80">The right answer was:</div>
                  <div className="text-lg text-white underline">{getCorrectText()}</div>
                </div>
              )}
            </div>
            <Button size="lg" className="w-full" onClick={nextQuestion}>
              {currentIndex < gameWords.length - 1 ? 'Next Question' : 'Finish Battle'}
            </Button>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { GameScreen, GameState, ShopItem, UserProfile, VocabWord } from './types';
import { INITIAL_USER, DEMO_WORDS } from './constants';
import { AvatarDisplay } from './components/AvatarDisplay';
import { Button } from './components/ui/Button';
import { BattleArena } from './components/BattleArena';
import { Shop } from './components/Shop';
import { Inventory } from './components/Inventory';
import { WordManager } from './components/admin/WordManager';
import { Settings, Play, ShoppingBag, BookOpen, Star, Sparkles, User } from 'lucide-react';

const App: React.FC = () => {
  // State initialization with localStorage persistence
  const [user, setUser] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('vq_user');
    if (saved) {
      const parsed = JSON.parse(saved);
      // Merge with INITIAL_USER to ensure new fields are present
      return { ...INITIAL_USER, ...parsed };
    }
    return INITIAL_USER;
  });

  const [words, setWords] = useState<VocabWord[]>(() => {
    // Bumped to v6 for multi-sentence support
    const saved = localStorage.getItem('vq_words_v6');
    return saved ? JSON.parse(saved) : DEMO_WORDS;
  });

  const [screen, setScreen] = useState<GameScreen>(GameScreen.HOME);
  const [lastBattleStats, setLastBattleStats] = useState<{score: number, gold: number, xp: number} | null>(null);

  // Persistence effects
  useEffect(() => {
    localStorage.setItem('vq_user', JSON.stringify(user));
  }, [user]);

  useEffect(() => {
    localStorage.setItem('vq_words_v6', JSON.stringify(words));
  }, [words]);

  // Actions
  const handleBattleComplete = (score: number, gold: number, xp: number) => {
    setUser(prev => ({
      ...prev,
      gold: prev.gold + gold,
      xp: prev.xp + xp,
      level: Math.floor((prev.xp + xp) / 1000) + 1,
      questsCompleted: (prev.questsCompleted || 0) + 1
    }));
    setLastBattleStats({ score, gold, xp });
    setScreen(GameScreen.HOME);
  };

  const handlePurchase = (item: ShopItem) => {
    if (user.gold >= item.price && !user.inventory.includes(item.id)) {
      setUser(prev => ({
        ...prev,
        gold: prev.gold - item.price,
        inventory: [...prev.inventory, item.id]
      }));
    }
  };

  const handleEquip = (item: ShopItem) => {
    setUser(prev => ({
      ...prev,
      equipped: {
        ...prev.equipped,
        [item.type]: item.id
      }
    }));
  };

  const handleUnequip = (type: 'HEAD' | 'FACE' | 'HAND' | 'PET') => {
    setUser(prev => {
        const newEquipped = { ...prev.equipped };
        delete newEquipped[type];
        return {
            ...prev,
            equipped: newEquipped
        };
    });
  };

  const handleUpdateName = (name: string) => {
    setUser(prev => ({ ...prev, name }));
  };

  const renderScreen = () => {
    switch (screen) {
      case GameScreen.BATTLE:
        return (
          <BattleArena 
            words={words} 
            user={user}
            onComplete={handleBattleComplete} 
            onExit={() => setScreen(GameScreen.HOME)} 
          />
        );

      case GameScreen.SHOP:
        return (
          <Shop 
            user={user} 
            onPurchase={handlePurchase} 
            onEquip={handleEquip}
            onClose={() => setScreen(GameScreen.HOME)}
          />
        );

      case GameScreen.INVENTORY:
        return (
          <Inventory 
            user={user} 
            onEquip={handleEquip}
            onUnequip={handleUnequip}
            onUpdateName={handleUpdateName}
            onClose={() => setScreen(GameScreen.HOME)}
          />
        );

      case GameScreen.PARENT_ZONE:
        return (
          <WordManager 
            currentWords={words} 
            onUpdateWords={setWords} 
            onClose={() => setScreen(GameScreen.HOME)} 
          />
        );

      case GameScreen.HOME:
      default:
        return (
          <div className="flex flex-col items-center justify-center min-h-screen p-4 animate-in fade-in duration-500">
            {/* Logo area */}
            <div className="text-center mb-8 relative">
              <h1 className="text-5xl md:text-7xl font-black text-transparent bg-clip-text bg-gradient-to-r from-indigo-400 via-purple-400 to-pink-400 drop-shadow-sm mb-2">
                VocabQuest
              </h1>
              <p className="text-xl text-slate-400 font-bold tracking-wide uppercase">Hero's Journey</p>

              <button 
                onClick={() => setScreen(GameScreen.PARENT_ZONE)}
                className="absolute -top-10 right-0 p-2 text-slate-700 hover:text-slate-500"
                title="Parent Zone"
              >
                <Settings size={20} />
              </button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8 w-full max-w-4xl">
              <div 
                className="bg-slate-800 rounded-3xl p-8 border-b-8 border-slate-950 flex flex-col items-center relative overflow-hidden cursor-pointer hover:bg-slate-800/80 transition-colors group"
                onClick={() => setScreen(GameScreen.INVENTORY)}
              >
                 <div className="absolute top-0 w-full h-full bg-indigo-500/5 z-0 pointer-events-none group-hover:bg-indigo-500/10 transition-colors"></div>
                 <div className="z-10 mb-6 group-hover:scale-105 transition-transform">
                    <AvatarDisplay user={user} size="lg" />
                 </div>
                 <div className="w-full z-10 space-y-3">
                    <h2 className="text-3xl font-bold text-center mb-1">{user.name}</h2>
                    <div className="flex justify-center gap-4 text-sm font-bold text-slate-400 uppercase tracking-wider mb-4">
                      <span>Lvl {user.level}</span>
                      <span>•</span>
                      <span>{user.xp} XP</span>
                    </div>
                    <div className="bg-slate-900 rounded-xl p-4 flex justify-between items-center border border-slate-700">
                       <span className="text-yellow-400 font-bold flex items-center gap-2">
                         <div className="bg-yellow-500/20 p-2 rounded-lg">💰</div> 
                         {user.gold} Gold
                       </span>
                       <span className="text-indigo-400 font-bold flex items-center gap-2">
                         {words.length} Words <div className="bg-indigo-500/20 p-2 rounded-lg"><BookOpen size={16}/></div>
                       </span>
                    </div>
                 </div>
              </div>

              <div className="flex flex-col gap-4 justify-center">
                {lastBattleStats && (
                  <div className="bg-green-500/10 border border-green-500/30 p-4 rounded-2xl mb-4 animate-in slide-in-from-right">
                    <h3 className="text-green-400 font-bold flex items-center gap-2 mb-1">
                      <Sparkles size={18} /> Battle Report
                    </h3>
                    <p className="text-sm text-green-200">
                      You scored {lastBattleStats.score} pts and earned {lastBattleStats.gold} gold!
                    </p>
                  </div>
                )}

                <Button 
                  size="lg" 
                  className="w-full h-24 text-2xl relative overflow-hidden group"
                  onClick={() => setScreen(GameScreen.BATTLE)}
                >
                  <div className="absolute inset-0 bg-gradient-to-r from-indigo-600 to-purple-600 group-hover:scale-105 transition-transform duration-500"></div>
                  <div className="relative z-10 flex items-center gap-3">
                    <Play fill="currentColor" size={32} /> Start Adventure
                  </div>
                </Button>

                <div className="grid grid-cols-2 gap-4">
                    <Button variant="secondary" className="w-full h-20 text-lg flex-col gap-1" onClick={() => setScreen(GameScreen.INVENTORY)}>
                        <div className="flex items-center gap-2"><User size={24}/> My Hero</div>
                    </Button>
                    <Button variant="secondary" className="w-full h-20 text-lg flex-col gap-1" onClick={() => setScreen(GameScreen.SHOP)}>
                        <div className="flex items-center gap-2"><ShoppingBag size={24} /> Shop</div>
                    </Button>
                </div>

                <div className="grid grid-cols-2 gap-4 mt-2">
                  <div className="bg-slate-800 p-4 rounded-2xl text-center border-b-4 border-slate-900">
                    <div className="text-3xl font-black text-slate-600 mb-1">0</div>
                    <div className="text-xs text-slate-500 uppercase font-bold">Daily Streak</div>
                  </div>
                  <div className="bg-slate-800 p-4 rounded-2xl text-center border-b-4 border-slate-900">
                    <div className="text-3xl font-black text-yellow-500 mb-1 flex justify-center items-center gap-1">
                      {user.questsCompleted || 0} <Star fill="currentColor" size={20}/>
                    </div>
                    <div className="text-xs text-slate-500 uppercase font-bold">Quests Done</div>
                  </div>
                </div>
              </div>
            </div>
          </div>
        );
    }
  };

  return (
    <div className="min-h-screen bg-slate-900 text-white font-sans selection:bg-indigo-500 selection:text-white flex flex-col">
      {renderScreen()}
    </div>
  );
};

export default App;

import React, { useMemo, useState } from 'react';
import { UserProfile, ShopItem } from '../types';
import { SHOP_ITEMS } from '../constants';
import { Button } from './ui/Button';
import { AvatarDisplay } from './AvatarDisplay';
import { ArrowLeft, XCircle, Edit2, Check, X } from 'lucide-react';

interface InventoryProps {
  user: UserProfile;
  onEquip: (item: ShopItem) => void;
  onUnequip: (type: 'HEAD' | 'FACE' | 'HAND' | 'PET') => void;
  onUpdateName: (name: string) => void;
  onClose: () => void;
}

export const Inventory: React.FC<InventoryProps> = ({ user, onEquip, onUnequip, onUpdateName, onClose }) => {
  const [isEditingName, setIsEditingName] = useState(false);
  const [tempName, setTempName] = useState(user.name);

  const ownedItems = useMemo(() => 
    SHOP_ITEMS.filter(item => user.inventory.includes(item.id)), 
  [user.inventory]);

  // Calculate stats
  const bonuses = useMemo(() => {
    let gold = 0;
    let xp = 0;
    Object.values(user.equipped).forEach(id => {
        const item = SHOP_ITEMS.find(i => i.id === id);
        if (item?.bonus?.type === 'GOLD') gold += item.bonus.value;
        if (item?.bonus?.type === 'XP') xp += item.bonus.value;
    });
    return { gold, xp };
  }, [user.equipped]);

  const categories: ('HEAD' | 'FACE' | 'HAND' | 'PET')[] = ['HEAD', 'FACE', 'HAND', 'PET'];

  const handleSaveName = () => {
    if (tempName.trim()) {
      onUpdateName(tempName.trim());
      setIsEditingName(false);
    }
  };

  const handleCancelName = () => {
    setTempName(user.name);
    setIsEditingName(false);
  };

  return (
    <div className="p-4 md:p-6 max-w-5xl mx-auto pb-20 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="flex items-center gap-4 mb-8">
        <Button variant="secondary" size="sm" onClick={onClose}><ArrowLeft size={20} /></Button>
        <h2 className="text-3xl font-black text-white">My Hero & Gear</h2>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-8">

        {/* Left Col: Avatar & Active Stats */}
        <div className="bg-slate-800 rounded-3xl p-6 border-2 border-slate-700 flex flex-col items-center h-fit">
            <div className="mb-6 scale-110">
                <AvatarDisplay user={user} size="lg" />
            </div>

            <div className="w-full flex flex-col items-center mb-6">
                {isEditingName ? (
                    <div className="flex items-center gap-2 w-full">
                        <input 
                            type="text"
                            value={tempName}
                            onChange={(e) => setTempName(e.target.value)}
                            onKeyDown={(e) => e.key === 'Enter' && handleSaveName()}
                            className="bg-slate-900 border-2 border-indigo-500 rounded-xl px-4 py-2 text-white font-bold w-full focus:outline-none"
                            autoFocus
                            maxLength={15}
                        />
                        <button 
                            onClick={handleSaveName}
                            className="bg-green-500 p-2 rounded-xl text-white hover:bg-green-400 transition-colors"
                        >
                            <Check size={20} />
                        </button>
                        <button 
                            onClick={handleCancelName}
                            className="bg-slate-700 p-2 rounded-xl text-white hover:bg-slate-600 transition-colors"
                        >
                            <X size={20} />
                        </button>
                    </div>
                ) : (
                    <div className="flex items-center gap-2 group">
                        <h3 className="text-2xl font-bold">{user.name}</h3>
                        <button 
                            onClick={() => setIsEditingName(true)}
                            className="text-slate-500 hover:text-indigo-400 transition-colors p-1"
                        >
                            <Edit2 size={18} />
                        </button>
                    </div>
                )}
            </div>

            <div className="w-full bg-slate-900 rounded-xl p-4 space-y-3 border border-slate-800">
                <h4 className="text-slate-400 text-xs font-bold uppercase tracking-widest mb-2">Active Bonuses</h4>
                <div className="flex justify-between items-center text-yellow-400 font-bold text-lg">
                    <span className="flex items-center gap-2">💰 Gold Bonus</span>
                    <span>+{bonuses.gold}%</span>
                </div>
                <div className="flex justify-between items-center text-purple-400 font-bold text-lg">
                    <span className="flex items-center gap-2">✨ XP Bonus</span>
                    <span>+{bonuses.xp}%</span>
                </div>
            </div>
        </div>

        {/* Right Col: Inventory Grid */}
        <div className="md:col-span-2 space-y-6">

            {categories.map(cat => {
                const categoryItems = ownedItems.filter(i => i.type === cat);
                const equippedId = user.equipped[cat];

                return (
                    <div key={cat} className="bg-slate-800/50 rounded-2xl p-4 border border-slate-700">
                        <div className="flex justify-between items-center mb-4">
                            <h3 className="font-bold text-slate-300 flex items-center gap-2">
                                {cat === 'HEAD' && '🧢 Headgear'}
                                {cat === 'FACE' && '😎 Face Accessories'}
                                {cat === 'HAND' && '🗡️ Hand Items'}
                                {cat === 'PET' && '🐾 Pets'}
                            </h3>
                            {equippedId && (
                                <button 
                                    onClick={() => onUnequip(cat)}
                                    className="text-xs text-red-400 hover:text-red-300 flex items-center gap-1 font-bold bg-red-950/30 px-2 py-1 rounded-lg"
                                >
                                    <XCircle size={14}/> Unequip
                                </button>
                            )}
                        </div>

                        {categoryItems.length === 0 ? (
                            <div className="text-slate-600 text-sm italic py-2">No items owned. Visit the shop!</div>
                        ) : (
                            <div className="flex flex-wrap gap-3">
                                {categoryItems.map(item => {
                                    const isEquipped = equippedId === item.id;
                                    return (
                                        <button
                                            key={item.id}
                                            onClick={() => onEquip(item)}
                                            className={`
                                                relative p-3 rounded-xl border-2 transition-all flex flex-col items-center w-24 group
                                                ${isEquipped 
                                                    ? 'bg-indigo-600/20 border-indigo-500 shadow-lg shadow-indigo-500/20' 
                                                    : 'bg-slate-700 border-slate-600 hover:bg-slate-600 hover:border-slate-500'
                                                }
                                            `}
                                        >
                                            <div className="text-3xl mb-2 group-hover:scale-110 transition-transform">{item.emoji}</div>
                                            <div className="text-xs font-bold text-center leading-tight truncate w-full text-slate-200">{item.name}</div>
                                            {item.bonus && (
                                                <div className={`absolute -top-2 -right-2 text-[10px] px-1.5 py-0.5 rounded-full font-bold shadow-sm ${item.bonus.type === 'GOLD' ? 'bg-yellow-600' : 'bg-purple-600'}`}>
                                                    +{item.bonus.value}%
                                                </div>
                                            )}
                                        </button>
                                    )
                                })}
                            </div>
                        )}
                    </div>
                );
            })}
        </div>

      </div>
    </div>
  );
};
